export default defineContract({
  name: 'billing',
  description: 'Handles user subscriptions and payment processing via Stripe.',

  dependencies: {
    modules: ['auth'], // Depends on auth for user authentication and types
  },

  exposes: {
    routes: [
      { method: 'POST', path: '/billing/subscribe', auth: true },
      // Add other billing routes here as needed (e.g., /billing/portal, /billing/cancel)
    ],
    functions: ['createSubscription'],
    types: ['Subscription', 'BillingError', 'StripeCustomerInfo'],
  },

  sideEffects: [
    'writes to: user_billing_info table',
    'interacts with: Stripe API (creates customers, subscriptions)',
  ],

  invariants: [
    'A user can only have one active subscription of a given type at a time.',
    'Stripe customer IDs must be unique per user.',
    'Subscription status in local DB must reflect Stripe status.',
  ],
});
