import { query } from '~/lib/db';
import { StripeCustomerInfo, Subscription } from '~/modules/billing/types';

/**
 * Retrieves a user's Stripe customer information from the database.
 * @param userId The ID of the user.
 * @returns The StripeCustomerInfo if found, otherwise null.
 */
export async function findUserStripeCustomerInfo(userId: string): Promise<StripeCustomerInfo | null> {
  const result = await query<{ user_id: string; stripe_customer_id: string; created_at: Date; updated_at: Date }>(
    `SELECT user_id, stripe_customer_id, created_at, updated_at
     FROM user_billing_info
     WHERE user_id = $1`,
    [userId]
  );

  if (result.rows.length === 0) {
    return null;
  }

  const row = result.rows[0];
  return {
    userId: row.user_id,
    stripeCustomerId: row.stripe_customer_id,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

/**
 * Upserts a user's Stripe customer ID into the database.
 * If a record exists for the user, it updates the stripe_customer_id.
 * Otherwise, it inserts a new record.
 * @param userId The ID of the user.
 * @param stripeCustomerId The Stripe customer ID.
 * @returns The upserted StripeCustomerInfo.
 */
export async function upsertUserStripeCustomerInfo(
  userId: string,
  stripeCustomerId: string
): Promise<StripeCustomerInfo> {
  const result = await query<{ user_id: string; stripe_customer_id: string; created_at: Date; updated_at: Date }>(
    `INSERT INTO user_billing_info (user_id, stripe_customer_id)
     VALUES ($1, $2)
     ON CONFLICT (user_id) DO UPDATE SET
       stripe_customer_id = EXCLUDED.stripe_customer_id,
       updated_at = NOW()
     RETURNING user_id, stripe_customer_id, created_at, updated_at`,
    [userId, stripeCustomerId]
  );

  const row = result.rows[0];
  return {
    userId: row.user_id,
    stripeCustomerId: row.stripe_customer_id,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

/**
 * Saves a new subscription record to the database.
 * @param subscription The subscription object to save.
 * @returns The saved Subscription object.
 */
export async function saveSubscription(subscription: Omit<Subscription, 'id' | 'createdAt' | 'updatedAt'>): Promise<Subscription> {
  const result = await query<Subscription>(
    `INSERT INTO subscriptions (user_id, stripe_customer_id, stripe_subscription_id, status, current_period_end)
     VALUES ($1, $2, $3, $4, $5)
     RETURNING id, user_id, stripe_customer_id, stripe_subscription_id, status, current_period_end, created_at, updated_at`,
    [
      subscription.userId,
      subscription.stripeCustomerId,
      subscription.stripeSubscriptionId,
      subscription.status,
      subscription.currentPeriodEnd,
    ]
  );
  return result.rows[0];
}

/**
 * Finds an active subscription for a given user.
 * @param userId The ID of the user.
 * @returns The active Subscription if found, otherwise null.
 */
export async function findActiveSubscriptionByUserId(userId: string): Promise<Subscription | null> {
  const result = await query<Subscription>(
    `SELECT id, user_id, stripe_customer_id, stripe_subscription_id, status, current_period_end, created_at, updated_at
     FROM subscriptions
     WHERE user_id = $1 AND status IN ('active', 'trialing', 'past_due')
     ORDER BY created_at DESC
     LIMIT 1`,
    [userId]
  );
  return result.rows.length > 0 ? result.rows[0] : null;
}
